package com.fasterxml.jackson.dataformat.xml.deser;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources/com/fasterxml/jackson/dataformat/xml/deser/requirement.feature",
    glue = "com.fasterxml.jackson.dataformat.xml.deser.steps",
    plugin = {"pretty", "html:target/cucumber-reports.html"}
)
public class CucumberTest {
}

package com.fasterxml.jackson.dataformat.xml.deser.steps;

import com.fasterxml.jackson.dataformat.xml.XmlMapper;
import com.fasterxml.jackson.dataformat.xml.annotation.JacksonXmlElementWrapper;
import com.fasterxml.jackson.dataformat.xml.annotation.JacksonXmlProperty;
import com.fasterxml.jackson.dataformat.xml.annotation.JacksonXmlRootElement;
import io.cucumber.java.en.Given;
import io.cucumber.java.en.Then;
import io.cucumber.java.en.When;
import org.junit.Assert;

import java.util.ArrayList;
import java.util.List;

public class StepDefs {

    @JacksonXmlRootElement(localName = "root")
    static class Root {
        @JacksonXmlElementWrapper(useWrapping = false)
        @JacksonXmlProperty(localName = "records")
        public List<Record> records = new ArrayList<Record>();
    }

    static class Record {
        public String name;
    }

    private String xmlInput;
    private Root result;
    private Exception exception;

    @Given("a POJO structure with a List of objects annotated with @JacksonXmlElementWrapper\\(useWrapping=false\\)")
    public void setupPojo() {
        // POJO is defined as static inner class
    }

    @Given("the XML input contains multiple elements for the list")
    public void setupXml() {
        // We will construct this in the next step
    }

    @Given("one of these elements is empty \\(e.g., <records></records>\\)")
    public void setupEmptyElement() {
        xmlInput = "<root>" +
                   "<records><name>First</name></records>" +
                   "<records></records>" + // Empty element
                   "<records><name>Third</name></records>" +
                   "</root>";
    }

    @When("the XML is deserialized")
    public void deserialize() {
        try {
            XmlMapper mapper = new XmlMapper();
            result = mapper.readValue(xmlInput, Root.class);
        } catch (Exception e) {
            exception = e;
        }
    }

    @Then("the list should contain an instantiated object for the empty element, not null")
    public void verifyNotNull() {
        if (exception != null) {
            exception.printStackTrace();
            Assert.fail("Deserialization failed: " + exception.getMessage());
        }
        Assert.assertNotNull(result);
        Assert.assertNotNull(result.records);
        Assert.assertEquals(3, result.records.size());

        // This is where the bug manifests. 
        // If the empty element is skipped or deserialized as null (when it should be an object), this assertion will help identify it.
        // Based on the failing tests seen earlier (NestedUnwrappedLists180Test), empty elements might be causing issues.
        Assert.assertNotNull("Second element (empty one) should not be null", result.records.get(1));
    }

    @Then("the list size should match the number of elements in the XML")
    public void verifySize() {
        Assert.assertEquals(3, result.records.size());
    }
}

